package s1ap

import "testing"

func TestDecodeUECapabilityInfoIndication(t *testing.T) {
	msg := decodeHex(t, ueCapabilityExampleHex)

	if msg.PDUType != "InitiatingMessage" || msg.ProcedureCode.Label != "UECapabilityInfoIndication" {
		t.Fatalf("pdu=%q proc=%q", msg.PDUType, msg.ProcedureCode.Label)
	}

	if mustIE(t, msg, idMMEUES1APID).Value != uint32(10) || mustIE(t, msg, idENBUES1APID).Value != uint32(810) {
		t.Fatal("UE id mismatch")
	}

	radioCap, ok := mustIE(t, msg, idUERadioCapability).Value.(string)
	if !ok || radioCap == "" {
		t.Fatalf("UERadioCapability = %v", mustIE(t, msg, idUERadioCapability).Value)
	}
}

const ueCapabilityExampleHex = ""
